export const PopoverDemo = (): Html => {
  const h = html<never>()

  return popoverShell({
    id: 'popover-demo',
    trigger: 'Open popover',
    title: 'Dimensions',
    description: 'Set the dimensions for the layer.',
    contentClassName: 'w-80',
    body: [
      h.div(
        [h.Class('grid gap-4')],
        [h.div([h.Class('space-y-2')], []), ...dimensionFields()],
      ),
    ],
  })
}

export const PopoverAlignments = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex gap-6')],
    [
      alignmentPopover('start', 'Start'),
      alignmentPopover('center', 'Center'),
      alignmentPopover('end', 'End'),
    ],
  )
}

const rtlPopover = (
  side: PopoverSide,
  trigger: string,
  title: string,
  description: string,
): Html =>
  popoverShell({
    id: `popover-rtl-${side}`,
    trigger,
    title,
    description,
    side,
    dir: 'rtl',
  })

export const PopoverRtl = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('grid gap-4')],
    [
      h.div(
        [h.Class('flex flex-wrap justify-center gap-2')],
        [
          rtlPopover('left', 'Left', 'Dimensions', 'Set the dimensions.'),
          rtlPopover('top', 'Top', 'Dimensions', 'Set the dimensions.'),
          rtlPopover('bottom', 'Bottom', 'Dimensions', 'Set the dimensions.'),
          rtlPopover('right', 'Right', 'Dimensions', 'Set the dimensions.'),
        ],
      ),
      h.div(
        [h.Class('flex flex-wrap justify-center gap-2')],
        [
          rtlPopover(
            'inline-start',
            'Inline Start',
            'Dimensions',
            'Set the dimensions.',
          ),
          rtlPopover(
            'inline-end',
            'Inline End',
            'Dimensions',
            'Set the dimensions.',
          ),
        ],
      ),
    ],
  )
}
